  1	import * as React from 'react';
  2	import { WorkloadGroupEntry } from '../../types/IstioObjects';
  3	import { IRow, TableVariant, ThProps } from '@patternfly/react-table';
  4	import {
  5	  Card,
  6	  CardBody,
  7	  CardHeader,
  8	  EmptyState,
  9	  EmptyStateBody,
 10	  EmptyStateVariant,
 11	  Title,
 12	  TitleSizes,
 13	  Tooltip,
 14	  TooltipPosition
 15	} from '@patternfly/react-core';
 16	import { kialiStyle } from 'styles/StyleUtils';
 17	import { KialiIcon } from '../../config/KialiIcon';
 18	import { LocalTime } from '../../components/Time/LocalTime';
 19	import { Labels } from '../../components/Label/Labels';
 20	import { PFBadge, PFBadges } from '../../components/Pf/PfBadges';
 21	import { SimpleTable } from 'components/Table/SimpleTable';
 22	import { infoStyle } from 'styles/IconStyle';
 23	
 24	type WorkloadEntriesProps = {
 25	  entries: WorkloadGroupEntry[];
 26	  namespace: string;
 27	  workload: string;
 28	};
 29	
 30	const emptyStyle = kialiStyle({
 31	  padding: 0,
 32	  margin: 0
 33	});
 34	
 35	const resourceListStyle = kialiStyle({
 36	  margin: '0 0 0.5rem 0',
 37	  $nest: {
 38	    '& > ul > li > span': {
 39	      float: 'left',
 40	      width: '125px',
 41	      fontWeight: 700
 42	    }
 43	  }
 44	});
 45	
 46	const iconStyle = kialiStyle({
 47	  display: 'inline-block'
 48	});
 49	
 50	export const WorkloadEntries: React.FC<WorkloadEntriesProps> = (props: WorkloadEntriesProps) => {
 51	  const columns: ThProps[] = [{ title: 'Name' }];
 52	
 53	  const noEntries: React.ReactNode = (
 54	    <EmptyState variant={EmptyStateVariant.sm} className={emptyStyle}>
 55	      <EmptyStateBody className={emptyStyle}>No Workload Entries in Workload {props.workload}</EmptyStateBody>
 56	    </EmptyState>
 57	  );
 58	
 59	  const rows: IRow[] = props.entries
 60	    .sort((p1: WorkloadGroupEntry, p2: WorkloadGroupEntry) => (p1.name < p2.name ? -1 : 1))
 61	    .map((entry, _entryIdx) => {
 62	      const entryProperties = (
 63	        <div key="properties-list" className={resourceListStyle}>
 64	          <ul style={{ listStyleType: 'none' }}>
 65	            <li>
 66	              <span>Created</span>
 67	              <div style={{ display: 'inline-block' }}>
 68	                <LocalTime time={entry.createdAt} />
 69	              </div>
 70	            </li>
 71	
 72	            <li>
 73	              <span>Service Account</span>
 74	              <div style={{ display: 'inline-block' }}>{entry.serviceAccountName ?? 'Not found'}</div>
 75	            </li>
 76	
 77	            <li>
 78	              <span>Labels</span>
 79	              <div style={{ display: 'inline-block' }}>
 80	                <Labels labels={entry.labels} expanded={true} />
 81	              </div>
 82	            </li>
 83	          </ul>
 84	        </div>
 85	      );
 86	
 87	      return {
 88	        cells: [
 89	          <span>
 90	            <div key="service-icon" className={iconStyle}>
 91	              <PFBadge badge={PFBadges.WorkloadEntry} size="sm" position={TooltipPosition.top} />
 92	            </div>
 93	
 94	            {entry.name}
 95	
 96	            <Tooltip
 97	              position={TooltipPosition.right}
 98	              content={<div style={{ textAlign: 'left' }}>{entryProperties}</div>}
 99	            >
100	              <KialiIcon.Info className={infoStyle} />
101	            </Tooltip>
102	          </span>
103	        ]
104	      };
105	    });
106	
107	  return (
108	    <Card isCompact={true} id="WorkloadEntriesCard">
109	      <CardHeader>
110	        <Title headingLevel="h5" size={TitleSizes.lg}>
111	          Workload Entries
112	        </Title>
113	      </CardHeader>
114	
115	      <CardBody>
116	        <SimpleTable
117	          label="Workload Entries List"
118	          columns={columns}
119	          rows={rows}
120	          variant={TableVariant.compact}
121	          emptyState={noEntries}
122	        />
123	      </CardBody>
124	    </Card>
125	  );
126	};

